import re

# Get data
business_data = locals()['var_functions.query_db:20']
reviews_data = locals()['var_functions.query_db:18']

# Extract categories function
def extract_categories(description):
    if not description:
        return []

    # Find category section
    cat_section = ''
    if 'services in' in description:
        cat_section = description.split('services in')[1].split('.')[0]
    elif 'services including' in description:
        cat_section = description.split('services including')[1].split('.')[0]
    elif 'offers a range of services' in description:
        cat_section = description.split('offers a range of services')[1].split('.')[0]
        if 'in' in cat_section:
            cat_section = cat_section.split('in')[1]
    elif 'offers enthusiasts a premier destination for' in description:
        cat_section = description.split('offers enthusiasts a premier destination for')[1].split('.')[0]

    if cat_section:
        # Split by 'and' or commas
        parts = re.split(r'\sand\s|,\s*', cat_section)
        categories = []
        for part in parts:
            part = part.strip()
            # Clean up
            part = re.sub(r'\sand$', '', part).strip()
            if part and len(part) < 50:
                categories.append(part)
        return categories

    return []

# Map business_id to categories
business_categories = {}
for biz in business_data:
    biz_id = biz['business_id']
    desc = biz.get('description', '')
    categories = extract_categories(desc)
    if categories:
        business_categories[biz_id] = categories

counts = {}
for biz_id in business_categories:
    counts[biz_id] = len(business_categories[biz_id])

print('__RESULT__:')
print(json.dumps({
    'total_businesses': len(business_data),
    'businesses_with_categories': len(business_categories),
    'categories_sample': {k: business_categories[k] for k in list(business_categories.keys())[:5]}
}))"}
